                            },
                            {
                                "linkId": "202",
                                "text": "<h2>Oireet</h2>"
                            },
                            {
                                "linkId": "6991",
                                "text": "Mitkä seuraavista oireista olet huomannut tapaturman jälkeen? (voit valita useamman kuin yhden)"
