{
    "hook": "questionnaire-completed",
    "prefetch": {
        "questionnaireResponse": {
            "resource": {
                "resourceType": "QuestionnaireResponse",
                "questionnaire": {
                    "reference": "https://www.ebmeds.org/form/api/forms/fhir/1952/{{operationMode}}/fi-fi",
                    "identifier": {
