                            },
                            {
                                "linkId": "7704",
                                "text": "Onko sinulla syömiseen liittyviä huolia tai oireita?"
                            },
                            {
                                "linkId": "7705",
                                "text": "Oletko itse tai onko joku muu ollut huolissaan syömisestäsi tai painostasi?"
                            },
                            {
                                "linkId": "7706",
                                "text": "Oletko itse tai onko joku muu epäillyt sinulla syömishäiriötä?"
                            },
                            {
                                "linkId": "7707",
                                "text": "Onko sinulla hoitokontakti oireesi vuoksi?"
                            },
